#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";

const ROOT = process.cwd();
const OUTPUT_DIR = path.join(ROOT, "scripts", "wellfit-dev-agent", "output");
const PROMPT_REL = "scripts/wellfit-dev-agent/output/next-agent-build-prompt.md";
const REPORT_REL = "scripts/wellfit-dev-agent/output/next-agent-build-proposal.md";

const PATHS = {
  backlog: "project-register/approved-agent-build-backlog.json",
  catalog: "project-register/agent-catalog.json",
  extensionPolicy: "project-register/agent-extension-policy.json",
  continuityMap: "project-register/continuity-dependency-map.json",
  architectPolicy: "project-register/agent-architect-policy.json"
};

const INELIGIBLE_STATUSES = new Set(["built", "blocked", "rejected", "duplicate", "superseded"]);
const ELIGIBLE_STATUSES = new Set(["approved_for_build", "approved_for_planning"]);

function readJson(relativePath) {
  return JSON.parse(fs.readFileSync(path.join(ROOT, relativePath), "utf8"));
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function unique(values) {
  return [...new Set(asArray(values).filter((value) => typeof value === "string" && value.trim().length > 0))];
}

function priorityRank(priority) {
  const match = String(priority ?? "").match(/^P(\d+)$/iu);
  return match ? Number.parseInt(match[1], 10) : 99;
}

function selectNext(backlog) {
  return asArray(backlog.entries)
    .filter((entry) => ELIGIBLE_STATUSES.has(entry.status) && !INELIGIBLE_STATUSES.has(entry.status))
    .sort((a, b) => {
      const orderA = Number.isFinite(Number(a.suggestedBuildOrder)) ? Number(a.suggestedBuildOrder) : 9999;
      const orderB = Number.isFinite(Number(b.suggestedBuildOrder)) ? Number(b.suggestedBuildOrder) : 9999;
      if (orderA !== orderB) return orderA - orderB;
      const priority = priorityRank(a.priority) - priorityRank(b.priority);
      if (priority !== 0) return priority;
      return String(a.id).localeCompare(String(b.id));
    })[0] ?? null;
}

function renderList(values) {
  const items = unique(values);
  return items.length ? items.map((value) => `- \`${value}\``).join("\n") : "- None recorded.";
}

function renderPrompt(entry, catalog, extensionPolicy, continuityMap) {
  const connectedAgents = unique(entry.connectedAgents);
  const connectedRegisters = unique(entry.connectedRegisters);
  const forbiddenFiles = unique(entry.forbiddenFiles);
  const allowedFiles = unique(entry.allowedFiles);
  const requiredDocs = unique(entry.requiredDocs);
  const requiredRegisters = unique(entry.requiredRegisters);
  const requiredValidationScripts = unique(entry.requiredValidationScripts);
  const catalogMatches = connectedAgents.filter((id) => asArray(catalog.entries).some((catalogEntry) => catalogEntry.id === id));
  const continuityOpenItems = asArray(continuityMap.entries).filter((item) => ["open", "in_progress", "review_required", "blocked", "device_test_required"].includes(item.status)).length;

  return `# Safe Codex Build Prompt: ${entry.proposedAgentName}\n\nMode: HUMAN_REVIEW_REQUIRED_BEFORE_EXECUTION\nGenerated by: WellFit Agent Architect & Proposal Agent (report-only)\nSource approved backlog id: \`${entry.id}\`\nRisk level: \`${entry.riskLevel}\`\nConnected agent count: ${connectedAgents.length}\nConnected register count: ${connectedRegisters.length}\n\n## First read before making changes\n\n- \`AGENTS.md\`\n- \`todolist/CURRENT_PROJECT_STATE.md\`\n- \`todolist/WORK_MAP.md\`\n- \`todolist/TODO_INDEX.md\`\n- \`project-register/agent-catalog.json\`\n- \`project-register/approved-agent-build-backlog.json\`\n- \`project-register/agent-extension-policy.json\`\n- \`project-register/continuity-dependency-map.json\`\n- \`project-register/risk-classifier.json\`\n- \`project-register/definition-of-done.json\`\n- \`project-register/product-readiness.json\`\n\n## Goal\n\nBuild exactly one report-only first version of \`${entry.proposedAgentName}\` if a human accepts this prompt. Do not build any additional future agents in the same task.\n\n## Why this agent is next\n\n- Status in approved backlog: \`${entry.status}\`.\n- Suggested build order: \`${entry.suggestedBuildOrder}\`.\n- Priority: \`${entry.priority}\`.\n- Reason: ${entry.reason}\n- Expected benefit: ${entry.expectedBenefit}\n- Extension-policy source of truth: \`${extensionPolicy.sourceOfTruth ?? "project-register/agent-extension-policy.json"}\`.\n- Current continuity entries needing attention: ${continuityOpenItems}.\n\n## Connected agents\n\n${renderList(connectedAgents)}\n\nCatalog-confirmed connected agents: ${catalogMatches.length ? catalogMatches.map((id) => `\`${id}\``).join(", ") : "None matched directly; keep proposal language conservative."}\n\n## Connected registers\n\n${renderList(connectedRegisters)}\n\n## Required docs\n\n${renderList(requiredDocs)}\n\n## Required registers\n\n${renderList(requiredRegisters)}\n\n## Required validation scripts\n\n${renderList(requiredValidationScripts)}\n\n## Allowed files\n\n${renderList(allowedFiles)}\n\n## Forbidden files\n\n${renderList(forbiddenFiles)}\n\n## Safety rules for the future build task\n\n- First version must be report-only unless a human explicitly approves a narrower runtime scope later.\n- Do not modify runtime/product code.\n- Do not modify app/**, components/**, lib/**, functions/**, firestore.rules, public/**, package.json, package-lock.json, firebase.json, .github/**, or native/unity/WellFitBuddyAR/**.\n- Do not modify token, NFT, wallet, payment, betting, reward authority, mission completion authority, health, child, location, privacy, legal, or compliance logic.\n- Do not create duplicate architecture or a parallel system.\n- Do not approve PRs, merge PRs, close PRs, enable auto-merge, enable auto-repair, repair files automatically, or deploy.\n- Keep humanReviewRequired=true for protected/high/critical or future-build completion evidence.\n\n## Required checks for the future build task\n\n- \`jq empty\` for every changed JSON register.\n- The new/updated report-only validation script for this one agent.\n- \`npm run agent:quality-gate\` when feasible.\n- \`git diff --check\`.\n\n## Human review gate\n\nBefore execution, a human reviewer must confirm that this prompt should become a Codex implementation task for exactly this one agent.\n`;
}

function renderReport(entry, promptRel, ready) {
  if (!entry) {
    return `# Next Agent Build Proposal\n\nGenerated: ${new Date().toISOString()}\nMode: REPORT_ONLY\nResult: NO_ELIGIBLE_AGENT\nNEXT_AGENT_BUILD_PROPOSAL_READY=false\n\nNo approved_for_build or approved_for_planning backlog entry is currently eligible after skipping built, blocked, rejected, duplicate, and superseded entries.\n`;
  }

  const connectedAgents = unique(entry.connectedAgents);
  const connectedRegisters = unique(entry.connectedRegisters);
  return `# Next Agent Build Proposal\n\nGenerated: ${new Date().toISOString()}\nMode: REPORT_ONLY\nResult: ${ready ? "PASS" : "FAIL"}\nNEXT_AGENT_BUILD_PROPOSAL_READY=${ready ? "true" : "false"}\n\n## Selected Agent\n\n- Proposed agent: ${entry.proposedAgentName}\n- Source approved backlog id: \`${entry.id}\`\n- Backlog status: \`${entry.status}\`\n- Suggested build order: \`${entry.suggestedBuildOrder}\`\n- Priority: \`${entry.priority}\`\n- Risk level: \`${entry.riskLevel}\`\n- Human review required: true\n\n## Why This Agent\n\n${entry.reason}\n\nExpected benefit: ${entry.expectedBenefit}\n\n## Connected Agent Count\n\n- connectedAgentCount: ${connectedAgents.length}\n\n${renderList(connectedAgents)}\n\n## Connected Register Count\n\n- connectedRegisterCount: ${connectedRegisters.length}\n\n${renderList(connectedRegisters)}\n\n## Generated Prompt\n\n- Location: \`${promptRel}\`\n\n## Safety Confirmations\n\n- Never creates the selected future agent: true\n- Never builds more than one future agent: true\n- Never modifies runtime files: true\n- Never approves, merges, closes, repairs, enables auto-merge, enables auto-repair, or deploys: true\n\n## Next Recommended Action\n\nReview \`${promptRel}\` and execute the next approved agent build only if a human accepts the prompt.\n`;
}

function main() {
  const backlog = readJson(PATHS.backlog);
  const catalog = readJson(PATHS.catalog);
  const extensionPolicy = readJson(PATHS.extensionPolicy);
  const continuityMap = readJson(PATHS.continuityMap);
  readJson(PATHS.architectPolicy);

  const selected = selectNext(backlog);
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });

  const ready = Boolean(selected);
  if (selected) fs.writeFileSync(path.join(ROOT, PROMPT_REL), renderPrompt(selected, catalog, extensionPolicy, continuityMap), "utf8");
  fs.writeFileSync(path.join(ROOT, REPORT_REL), renderReport(selected, PROMPT_REL, ready), "utf8");

  console.log(`WellFit next agent build proposal report written: ${REPORT_REL}`);
  if (selected) console.log(`WellFit next agent build prompt written: ${PROMPT_REL}`);
  console.log("Mode: REPORT_ONLY");
  console.log("Never creates agents automatically: true");
  console.log("Never modifies runtime files: true");
  console.log("Never approves PRs: true");
  console.log("Never merges PRs: true");
  console.log("Never repairs files: true");
  console.log("Never deploys: true");
  console.log(`NEXT_AGENT_BUILD_PROPOSAL_READY=${ready ? "true" : "false"}`);
  console.log(`Result: ${ready ? "PASS" : "NO_ELIGIBLE_AGENT"}`);
  if (!ready) process.exit(1);
}

main();
